495→/**
496→ * Queries task status directly from the database.
497→ */
498→export async function getTaskStatus(
499→  surreal: Surreal,
500→  taskId: string,
501→): Promise<string> {
502→  const taskRecord = new RecordId("task", taskId);
503→  const rows = (await surreal.query(
504→    `SELECT status FROM $task;`,
505→    { task: taskRecord },
506→  )) as Array<Array<{ status: string }>>;
507→  const result = rows[0]?.[0];
