 78→ * until a terminal event or timeout.
 79→ */
 80→export async function collectSessionEvents(
 81→  baseUrl: string,
 82→  streamUrl: string,
 83→  options: {
 84→    timeoutMs?: number;
 85→    stopOnTypes?: string[];
 86→    maxEvents?: number;
 87→    authHeaders?: Record<string, string>;
 88→  } = {},
 89→): Promise<AgentStreamEvent[]> {
 90→  const timeoutMs = options.timeoutMs ?? 15_000;
 91→  const stopOnTypes = options.stopOnTypes ?? ["agent_done", "agent_error"];
 92→  const maxEvents = options.maxEvents ?? 1000;
 93→
 94→  const response = await fetch(`${baseUrl}${streamUrl}`, {
 95→    headers: { Accept: "text/event-stream", ...options.authHeaders },
 96→  });
 97→
 98→  if (!response.ok || !response.body) {
 99→    throw new Error(`Failed to open session event stream (${response.status})`);
100→  }
101→
102→  const reader = response.body.getReader();
103→  const decoder = new TextDecoder();
104→  const events: AgentStreamEvent[] = [];
105→  let buffer = "";
106→
107→  const timeout = setTimeout(() => {
108→    void reader.cancel();
109→  }, timeoutMs);
110→
111→  try {
112→    while (true) {
113→      const { value, done } = await reader.read();
114→      if (done) break;
115→
116→      buffer += decoder.decode(value, { stream: true });
117→      const segments = buffer.split("\n\n");
118→      buffer = segments.pop() ?? "";
119→
120→      for (const segment of segments) {
121→        const dataLine = segment
122→          .split("\n")
123→          .find((line) => line.startsWith("data: "));
124→        if (!dataLine) continue;
125→
126→        const event = JSON.parse(
127→          dataLine.slice("data: ".length),
128→        ) as AgentStreamEvent;
129→        events.push(event);
130→
131→        if (stopOnTypes.includes(event.type) || events.length >= maxEvents) {
132→          return events;
133→        }
134→      }
135→    }
136→  } finally {
137→    clearTimeout(timeout);
138→    reader.releaseLock();
139→  }
140→
141→  return events;
142→}
