 15→function makePushEvent(overrides: {
 16→  ref?: string;
 17→  defaultBranch?: string;
 18→  commits?: Array<{
 19→    id: string;
 20→    message: string;
 21→    timestamp: string;
 22→    url: string;
 23→    author: { name: string; email: string; username?: string };
 24→  }>;
 25→}) {
 26→  const defaultBranch = overrides.defaultBranch ?? "main";
 27→  return {
 28→    ref: overrides.ref ?? `refs/heads/${defaultBranch}`,
 29→    repository: {
 30→      full_name: "acme/brain",
 31→      default_branch: defaultBranch,
 32→      html_url: "https://github.com/acme/brain",
 33→    },
 34→    commits: overrides.commits ?? [],
 35→  };
 36→}
