113→describe("US-UI-005: Dual-label audit trail shows actor and accountable human for every action", () => {
114→  // -- Happy path: agent action with dual-label --
115→
116→  it("Given the PM Agent created a task, when the task's audit trail is queried, then the result shows actor 'PM Agent' with type 'agent' and accountable human 'Marcus Oliveira'", async () => {
117→    const now = new Date();
118→    const taskRecord = new RecordId("task", randomUUID());
119→
120→    await surreal.query("CREATE $record CONTENT $content;", {
121→      record: taskRecord,
122→      content: {
123→        title: "Set up CI pipeline",
124→        status: "open",
125→        owner: agentIdentity,
126→        workspace: workspaceRecord,
127→        created_at: now,
128→        updated_at: now,
129→      },
130→    });
131→
132→    // Dual-label query: resolve owner identity and managed_by chain
133→    // Step 1: get actor identity
134→    const [actorRows] = await surreal.query<
135→      [Array<{ title: string; actor_name: string; actor_type: string; owner_id: RecordId }>]
136→    >(
137→      `SELECT title, owner.name AS actor_name, owner.type AS actor_type, owner AS owner_id FROM $record;`,
138→      { record: taskRecord },
