 63→// -- Helpers --
 64→
 65→async function createIdentity(
 66→  type: "human" | "agent" | "system",
 67→  role?: string,
 68→): Promise<RecordId<"identity", string>> {
 69→  const record = new RecordId("identity", randomUUID());
 70→  const content: Record<string, unknown> = {
 71→    name: `identity-${record.id}`,
 72→    type,
 73→    workspace: workspaceRecord,
 74→    created_at: new Date(),
 75→  };
 76→  if (role !== undefined) {
 77→    content.role = role;
 78→  }
 79→  await surreal.create(record).content(content);
 80→  return record;
 81→}
