 83→describe("US-UI-03-01: Authority resolves override then role default then blocked", () => {
 84→
 85→  // -- Human bypass --
 86→
 87→  it("Given a human identity, when checkAuthority is called for confirm_decision, then it returns auto (human bypass)", async () => {
 88→    const identity = await createIdentity("human", "owner");
 89→
 90→    const result = await checkAuthority({
 91→      surreal,
 92→      agentType: "code_agent",
 93→      action: "confirm_decision",
 94→      workspaceRecord,
 95→      identityRecord: identity,
 96→    });
 97→
 98→    expect(result).toBe("auto");
 99→  }, 30_000);
100→
101→  // -- Per-identity override takes precedence over role default --
102→
103→  it("Given an agent identity with role-default blocked for confirm_decision, when an authorized_to override grants auto, then override permission is returned", async () => {
104→    const identity = await createIdentity("agent", "code_agent");
105→
106→    // code_agent + confirm_decision = blocked by seed data
107→    // Create a per-identity override granting auto
108→    const [scopeRows] = await surreal.query<[Array<{ id: RecordId }>]>(
109→      "SELECT id FROM authority_scope WHERE agent_type = 'code_agent' AND action = 'confirm_decision' AND workspace IS NONE LIMIT 1;",
110→    );
111→    const scopeRecord = scopeRows[0].id;
112→
113→    await surreal.relate(
114→      identity,
115→      new RecordId("authorized_to", randomUUID()),
116→      scopeRecord,
117→      { permission: "auto", created_at: new Date() },
118→    ).output("after");
119→
120→    const result = await checkAuthority({
121→      surreal,
122→      agentType: "code_agent",
123→      action: "confirm_decision",
124→      workspaceRecord,
125→      identityRecord: identity,
126→    });
127→
128→    expect(result).toBe("auto");
129→  }, 30_000);
130→
131→  // -- Role-based resolution (identity.role matches authority_scope.agent_type) --
132→
133→  it("Given an agent identity with role architect, when checkAuthority is called with agentType code_agent for resolve_observation, then role-based permission (auto) is used instead of agent_type default (blocked)", async () => {
134→    const identity = await createIdentity("agent", "architect");
135→
136→    // architect + resolve_observation = auto (seed data)
137→    // code_agent + resolve_observation = blocked (seed data)
138→    // identity.role = architect should take precedence over agentType param
139→    const result = await checkAuthority({
140→      surreal,
141→      agentType: "code_agent",
142→      action: "resolve_observation",
143→      workspaceRecord,
144→      identityRecord: identity,
145→    });
146→
147→    expect(result).toBe("auto");
148→  }, 30_000);
149→
150→  // -- No role, no override -> falls back to agent_type default --
151→
152→  it("Given an agent identity with no role and no override, when checkAuthority is called, then agent_type default is used", async () => {
153→    const identity = await createIdentity("agent");
154→
155→    const result = await checkAuthority({
156→      surreal,
157→      agentType: "code_agent",
158→      action: "create_task",
159→      workspaceRecord,
160→      identityRecord: identity,
161→    });
162→
163→    expect(result).toBe("auto");
164→  }, 30_000);
165→
166→  // -- Fail-safe: no match at all --
167→
168→  it("Given an identity with no role, no override, and unknown agent_type, when checkAuthority is called, then blocked is returned", async () => {
169→    const identity = await createIdentity("agent");
170→
171→    const result = await checkAuthority({
172→      surreal,
173→      // @ts-expect-error -- testing unknown agent type fallback
174→      agentType: "unknown_type",
175→      action: "create_task",
176→      workspaceRecord,
177→      identityRecord: identity,
178→    });
179→
180→    expect(result).toBe("blocked");
181→  }, 30_000);
182→
183→  // -- Schema: authorized_to relation exists --
184→
185→  it("Given the schema is applied, when authorized_to table info is queried, then the table exists as a RELATION", async () => {
186→    const [info] = await surreal.query<[Record<string, unknown>]>(
187→      "INFO FOR TABLE authorized_to;",
188→    );
189→
190→    expect(info).toBeDefined();
191→  }, 30_000);
192→
193→  // -- Invalid permission rejected by schema --
194→
195→  it("Given an authorized_to override, when the permission value is not in the allowed enum, then the creation fails", async () => {
196→    const identity = await createIdentity("agent", "management");
197→
198→    const [scopes] = await surreal.query<[Array<{ id: RecordId }>]>(
199→      "SELECT id FROM authority_scope LIMIT 1;",
200→    );
201→
202→    let rejected = false;
203→    try {
204→      await surreal.query(
205→        `RELATE $identity->authorized_to->$scope
206→         SET permission = 'invalid_perm', created_at = $now;`,
207→        { identity, scope: scopes[0].id, now: new Date() },
208→      );
209→    } catch {
210→      rejected = true;
211→    }
212→
213→    // SurrealDB SCHEMAFULL with ASSERT should reject invalid permission values
214→    // If it doesn't throw, check that no record was actually created
215→    if (!rejected) {
216→      const [overrides] = await surreal.query<[Array<{ permission: string }>]>(
217→        "SELECT permission FROM authorized_to WHERE in = $identity AND permission = 'invalid_perm';",
218→        { identity },
219→      );
220→      // If the query didn't throw but also didn't persist, that counts as rejected
221→      rejected = overrides.length === 0;
222→    }
223→
224→    expect(rejected).toBe(true);
225→  }, 30_000);
226→});
