 31→beforeAll(async () => {
 32→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 33→  namespace = `smoke_identity_skeleton_${runId}`;
 34→  database = `skeleton_${Math.floor(Math.random() * 100000)}`;
 35→
 36→  surreal = new Surreal();
 37→  await surreal.connect(surrealUrl);
 38→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 39→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 40→  await surreal.use({ namespace });
 41→  await surreal.query(`DEFINE DATABASE ${database};`);
 42→  await surreal.use({ namespace, database });
 43→
 44→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 45→  await surreal.query(schemaSql);
 46→
 47→  const now = new Date();
 48→
 49→  // Create workspace
 50→  workspaceRecord = new RecordId("workspace", randomUUID());
 51→  await surreal.create(workspaceRecord).content({
 52→    name: "Identity Skeleton Workspace",
 53→    status: "active",
