 13→ */
 14→
 15→const getRuntime = setupSmokeSuite("auth-rewiring");
 16→
 17→describe("US-UI-004: Auth resolves identity from person via spoke traversal", () => {
 18→  // Shared state: one user + workspace created once before all tests run.
 19→  // With --concurrent, all it() blocks run in parallel — creating users and workspaces
 20→  // inside each it() overloads the server and causes silent bootstrap failures.
 21→  let sharedUser: { headers: Record<string, string> };
 22→  let sharedWorkspace: { workspaceId: string; conversationId: string };
 23→
 24→  beforeAll(async () => {
 25→    const { baseUrl } = getRuntime();
 26→
 27→    sharedUser = await createTestUser(baseUrl, "auth-rewiring");
 28→    sharedWorkspace = await fetchJson<{ workspaceId: string; conversationId: string }>(
 29→      `${baseUrl}/api/workspaces`,
 30→      {
 31→        method: "POST",
 32→        headers: { "Content-Type": "application/json", ...sharedUser.headers },
 33→        body: JSON.stringify({ name: `Auth Rewiring Test ${Date.now()}` }),
 34→      },
 35→    );
 36→  }, 60_000);
 37→
 38→  // -- Session still references person --
 39→
 40→  it("Given a user signs up, when the session is queried, then session.person_id references a person record", async () => {
 41→    const { surreal } = getRuntime();
 42→
 43→    const [sessions] = await surreal.query<
 44→      [Array<{ person_id: RecordId }>]
 45→    >("SELECT person_id FROM session LIMIT 1;");
 46→
 47→    expect(sessions.length).toBeGreaterThan(0);
 48→    expect(sessions[0].person_id).toBeDefined();
 49→    expect((sessions[0].person_id as RecordId).table.name).toBe("person");
 50→  }, 60_000);
 51→
 52→  // -- Person has identity via spoke edge --
 53→
 54→  it("Given a user signs up and creates a workspace, when the identity_person spoke is queried, then the person has a linked identity with type human", async () => {
 55→    const { surreal } = getRuntime();
 56→
 57→    const wsRecord = new RecordId("workspace", sharedWorkspace.workspaceId);
 58→
 59→    const [identities] = await surreal.query<
 60→      [Array<{ id: RecordId; type: string; name: string }>]
 61→    >(
 62→      "SELECT id, type, name FROM identity WHERE workspace = $ws AND type = 'human' LIMIT 1;",
 63→      { ws: wsRecord },
 64→    );
 65→
 66→    expect(identities.length).toBeGreaterThan(0);
 67→    expect(identities[0].type).toBe("human");
 68→
 69→    // Verify spoke edge exists from this identity to a person
 70→    const [spokeEdges] = await surreal.query<[Array<{ out: RecordId }>]>(
 71→      "SELECT out FROM identity_person WHERE in = $identity LIMIT 1;",
 72→      { identity: identities[0].id },
 73→    );
 74→    expect(spokeEdges.length).toBeGreaterThan(0);
 75→    expect((spokeEdges[0].out as RecordId).table.name).toBe("person");
 76→  }, 60_000);
 77→
 78→  // -- Identity is member_of workspace --
 79→
 80→  it("Given a user creates a workspace, when member_of is queried, then the identity (not person) is the member", async () => {
 81→    const { surreal } = getRuntime();
 82→
 83→    const wsRecord = new RecordId("workspace", sharedWorkspace.workspaceId);
 84→    const [members] = await surreal.query<
 85→      [Array<{ in: RecordId; role: string }>]
 86→    >(
 87→      "SELECT in, role FROM member_of WHERE out = $ws LIMIT 1;",
 88→      { ws: wsRecord },
 89→    );
 90→
 91→    expect(members.length).toBeGreaterThan(0);
 92→    expect((members[0].in as RecordId).table.name).toBe("identity");
 93→    expect(members[0].role).toBe("owner");
 94→  }, 60_000);
 95→
 96→  // -- Chat context uses identity --
 97→
 98→  it("Given a user is logged in and has a workspace, when the user sends a chat message, then the chat pipeline processes the message using the user's identity as the actor", async () => {
 99→    const { baseUrl } = getRuntime();
100→
101→    // Send a message - the pipeline should resolve identity from person via spoke
102→    // We verify this works end-to-end (no crash from type mismatches)
103→    const chatResponse = await fetchJson<{ messageId: string }>(
104→      `${baseUrl}/api/chat/messages`,
105→      {
106→        method: "POST",
107→        headers: { "Content-Type": "application/json", ...sharedUser.headers },
108→        body: JSON.stringify({
109→          clientMessageId: `auth-test-${Date.now()}`,
110→          workspaceId: sharedWorkspace.workspaceId,
111→          conversationId: sharedWorkspace.conversationId,
112→          text: "Hello, testing identity-based chat context.",
113→        }),
114→      },
115→    );
116→
117→    expect(chatResponse.messageId).toBeDefined();
118→    expect(chatResponse.messageId.length).toBeGreaterThan(0);
119→  }, 60_000);
120→
121→  // -- Schema: session and account still use person_id --
122→
123→  it("Given the auth tables are unchanged, when schema info is queried, then session and account use person_id not identity_id", async () => {
124→    const { surreal } = getRuntime();
125→
126→    for (const table of ["session", "account"]) {
127→      const [info] = await surreal.query<[Record<string, unknown>]>(
128→        `INFO FOR TABLE ${table};`,
129→      );
130→
131→      const infoObj = info as unknown as Record<string, Record<string, string>>;
132→      const fieldMap = infoObj.fields ?? infoObj.fd ?? {};
133→      const fieldNames = Object.keys(fieldMap);
134→
135→      expect(fieldNames).toContain("person_id");
136→      expect(fieldNames).not.toContain("identity_id");
137→    }
138→  }, 60_000);
139→});
